INSERT INTO public.news (slug, title, excerpt, content, category, media_type, cover_image_url, youtube_url, is_published, published_at) VALUES
('bhola-health-camp-2026', 'ভোলায় বিনামূল্যে স্বাস্থ্য ক্যাম্পে ১২০০ রোগী সেবা পেলেন', 'উপকূলীয় ভোলায় তিনদিনব্যাপী মেডিকেল ক্যাম্পে বিশেষজ্ঞ চিকিৎসকদের তত্ত্বাবধানে ১২০০-এর বেশি রোগী বিনামূল্যে চিকিৎসা ও ওষুধ পেয়েছেন।', E'কুদরাত ফাউন্ডেশনের আয়োজনে ভোলা জেলার চরফ্যাশন উপজেলায় তিনদিনব্যাপী মেডিকেল ক্যাম্প সম্পন্ন হয়েছে। ১৫ জন বিশেষজ্ঞ চিকিৎসক ও ২৫ জন স্বেচ্ছাসেবক এই ক্যাম্পে অংশ নেন।\n\nক্যাম্পে শিশু, নারী ও বয়স্কদের জন্য আলাদা সেবা ইউনিট চালু ছিল। ১২০০-এর বেশি রোগী বিনামূল্যে চিকিৎসা ও প্রয়োজনীয় ওষুধ পেয়েছেন। এছাড়া ৩৫০ জনকে চশমা ও ৬০ জনকে ছানি অপারেশনের জন্য রেফার করা হয়েছে।', 'Health', 'image', '/img/portfolio-health.jpg', NULL, true, now() - interval '2 days'),
('jamuna-flood-relief-update', 'যমুনা পাড়ে বন্যা ত্রাণ: ৫০০ পরিবারে শুকনো খাবার বিতরণ', 'সিরাজগঞ্জের চরাঞ্চলে আকস্মিক বন্যায় ক্ষতিগ্রস্ত ৫০০ পরিবারের মাঝে শুকনো খাবার, পানি বিশুদ্ধকরণ ট্যাবলেট ও স্যালাইন বিতরণ সম্পন্ন।', E'গত সপ্তাহে যমুনা নদীর পানি বিপদসীমা অতিক্রম করায় সিরাজগঞ্জের চৌহালী ও কাজিপুর উপজেলার চরাঞ্চলে ব্যাপক বন্যা দেখা দেয়। কুদরাত ফাউন্ডেশনের জরুরি ত্রাণ দলটি দ্রুত ঘটনাস্থলে পৌঁছে ৫০০ পরিবারের মাঝে ত্রাণসামগ্রী বিতরণ করেছে।\n\nপ্রতিটি পরিবার পেয়েছে: ৫ কেজি চিড়া, ১ কেজি গুড়, পানি বিশুদ্ধকরণ ট্যাবলেট, ORS স্যালাইন এবং প্রয়োজনীয় ওষুধ।', 'Relief', 'image', '/img/portfolio-flood.jpg', NULL, true, now() - interval '5 days'),
('women-entrepreneurs-launch', 'নারী উদ্যোক্তাদের জন্য সেলাই প্রশিক্ষণ কেন্দ্র উদ্বোধন', 'রংপুরে ৪০ জন নারীর জন্য আধুনিক সেলাই ও বুটিক প্রশিক্ষণ কেন্দ্র চালু হয়েছে। ৬ মাসের প্রশিক্ষণ শেষে তারা স্বাবলম্বী হওয়ার সুযোগ পাবেন।', E'রংপুরের পীরগঞ্জ উপজেলায় নারী উদ্যোক্তা উন্নয়ন কেন্দ্রের আনুষ্ঠানিক উদ্বোধন হয়েছে। প্রথম ব্যাচে ৪০ জন নারীকে আধুনিক সেলাই, বুটিক ডিজাইন ও মার্কেটিং বিষয়ে প্রশিক্ষণ দেওয়া হবে।\n\nপ্রশিক্ষণ শেষে প্রত্যেককে একটি করে সেলাই মেশিন ও স্টার্টআপ পুঁজি প্রদান করা হবে।', 'Empowerment', 'image', '/img/portfolio-women.jpg', NULL, true, now() - interval '8 days'),
('safe-water-documentary', 'নিরাপদ পানির জন্য আমাদের লড়াই — তথ্যচিত্র', 'আট গ্রামে নিরাপদ পানি পৌঁছে দেওয়ার পেছনের গল্প নিয়ে কুদরাত ফাউন্ডেশনের নতুন তথ্যচিত্র।', NULL, 'Documentary', 'video', NULL, 'https://www.youtube.com/watch?v=dQw4w9WgXcQ', true, now() - interval '10 days'),
('winter-drive-2026-announce', 'শীতবস্ত্র বিতরণ ২০২৬: ১০ হাজার কম্বল লক্ষ্য', 'এই শীতে উত্তরবঙ্গের শীতার্ত মানুষের পাশে দাঁড়াতে আমাদের নতুন উদ্যোগ — সবার অংশগ্রহণ কাম্য।', E'প্রতি বছরের মতো এবারও কুদরাত ফাউন্ডেশন দেশের উত্তরাঞ্চলের শীতার্ত মানুষের জন্য শীতবস্ত্র বিতরণ কর্মসূচি গ্রহণ করেছে। এবারের লক্ষ্যমাত্রা ১০,০০০ কম্বল।\n\nআপনার ছোট্ট অবদানও বদলে দিতে পারে একজনের শীতের রাত। প্রতিটি কম্বলের মূল্য মাত্র ৫০০ টাকা।', 'Campaign', 'image', '/img/portfolio-winter.jpg', NULL, true, now() - interval '14 days'),
('education-impact-story', 'বিদ্যালয় সংস্কার: শিক্ষার্থীদের চোখে নতুন আলো', 'নেত্রকোনার একটি প্রত্যন্ত প্রাথমিক বিদ্যালয় সংস্কারের পর শিক্ষার্থী উপস্থিতি বেড়েছে ৭০%। তাদের গল্প শুনুন।', NULL, 'Story', 'video', '/img/portfolio-education.jpg', 'https://www.youtube.com/watch?v=ScMzIvxBSi4', true, now() - interval '18 days'),
('water-project-milestone', '৮ গ্রামে নিরাপদ পানি: ১২০টি গভীর নলকূপ স্থাপন সম্পন্ন', 'খুলনার উপকূলীয় ৮ গ্রামে আর্সেনিকমুক্ত গভীর নলকূপ স্থাপনের কাজ সফলভাবে সম্পন্ন হয়েছে।', E'খুলনার দাকোপ ও কয়রা উপজেলার ৮টি গ্রামে মোট ১২০টি গভীর নলকূপ স্থাপনের কাজ সম্পন্ন হয়েছে। এর ফলে প্রায় ৬,০০০ মানুষ এখন নিরাপদ ও আর্সেনিকমুক্ত পানি পাচ্ছেন।\n\nপ্রতিটি নলকূপের সাথে রয়েছে পানি পরীক্ষার সনদ এবং তিন বছরের রক্ষণাবেক্ষণ নিশ্চয়তা।', 'Project', 'image', '/img/portfolio-water.jpg', NULL, true, now() - interval '22 days'),
('annual-report-2025-text', 'বার্ষিক প্রতিবেদন ২০২৫: এক ঝলকে কুদরাত ফাউন্ডেশন', 'গত বছর ৪৮টি জেলায় ৩২,০০০+ মানুষের জীবনে সরাসরি প্রভাব রেখেছে কুদরাত ফাউন্ডেশন।', E'২০২৫ সালে কুদরাত ফাউন্ডেশনের কার্যক্রমের কিছু গুরুত্বপূর্ণ পরিসংখ্যান:\n\n• ৪৮টি জেলায় কার্যক্রম পরিচালনা\n• ৩২,০০০+ সরাসরি উপকারভোগী\n• ১২০টি গভীর নলকূপ স্থাপন\n• ১৮টি স্বাস্থ্য ক্যাম্প\n• ২,৪০০ শিক্ষার্থীকে শিক্ষা উপকরণ বিতরণ\n• ৬৫০ পরিবারকে শীতবস্ত্র সহায়তা\n\nআপনার অব্যাহত সহযোগিতার জন্য আন্তরিক কৃতজ্ঞতা।', 'Report', 'text', NULL, NULL, true, now() - interval '28 days')
